class ExamRoom {
    int n;
    TreeSet<Integer> students;

    public ExamRoom(int n) {
        this.n = n;
        students = new TreeSet<>();
    }

    public int seat() {
        if (students.isEmpty()) {
            students.add(0);
            return 0;
        }
        int maxDistance = students.first();
        int prevStudent = -1;
        int bestSeat = 0;
        for (int student : students) {
            if (prevStudent != -1) {
                int distance = (student - prevStudent) / 2;
                if (distance > maxDistance) {
                    maxDistance = distance;
                    bestSeat = prevStudent + distance;
                }
            }
            prevStudent = student;
        }
        int distanceToEnd = n - 1 - students.last();
        if (distanceToEnd > maxDistance) {
            bestSeat = n - 1;
        }
        students.add(bestSeat);
        return bestSeat;
    }

    public void leave(int p) {
        students.remove(p);
    }
}

